import React from 'react';
import { PortalAdd } from '@capital/component';
import { PlayerRoot } from './PlayerRoot';

let mounted = false;

/**
 * 将全局悬浮播放器挂载到 Tailchat 的全局 Portal 层
 * (复用宿主应用已有的 React/ReactDOM 实例，无需额外打包 react-dom)
 */
export function mountGlobalPlayer() {
  if (mounted) return;
  mounted = true;

  PortalAdd(<PlayerRoot />);
}
